document.addEventListener('DOMContentLoaded',function(){const tabTitles=document.querySelectorAll('.hc-blog-sidebar-tabber--tab_title');const tabs=document.querySelectorAll('.hc-blog-sidebar-tabber--tab');tabs.forEach(tab=>{tab.style.transition='opacity 0.3s ease-in-out';tab.style.opacity=tab.style.display==='none'?'0':'1'});tabTitles.forEach(title=>{title.addEventListener('click',function(){const target=this.getAttribute('data-target');tabTitles.forEach(t=>t.classList.remove('active'));this.classList.add('active');tabs.forEach(tab=>{tab.style.opacity='0';setTimeout(()=>{tab.style.display='none';if(tab.getAttribute('data-tab')===target){tab.style.display='block';setTimeout(()=>{tab.style.opacity='1'},50)}},300)})})})})